import com.amazonaws.auth.AWSStaticCredentialsProvider
import com.amazonaws.auth.BasicAWSCredentials
import com.amazonaws.services.s3.AmazonS3ClientBuilder
import com.amazonaws.services.s3.model.{CreateBucketRequest, S3ObjectSummary}

class AWSService(accessKey: String, secretKey: String) {

  private val awsCredentials = new BasicAWSCredentials(accessKey, secretKey)
  private val s3Client = AmazonS3ClientBuilder.standard()
    .withRegion("us-west-2") // Change region as needed
    .withCredentials(new AWSStaticCredentialsProvider(awsCredentials))
    .build()

  def createBucket(bucketName: String): Unit = {
    val createBucketRequest = new CreateBucketRequest(bucketName, "us-west-2") // Specify region if needed
    s3Client.createBucket(createBucketRequest)
  }

  def listBuckets(): List[String] = {
    s3Client.listBuckets.asScala.map(_.getName).toList
  }

  def listObjectsInBucket(bucketName: String): List[String] = {
    val objects = s3Client.listObjects(bucketName)
    objects.getObjectSummaries.asScala.map(_.getKey).toList
  }
}

